-- ============================================================================
-- SJC Deal Book bootstrap seed (Deal-object, manual export 2026-07-14)
-- Source: Salesforce "internal sold transactions, PROPERTY SUB-TYPE = Dialysis"
--         export (290 rows -> 272 distinct deals, 251 priced/closed).
-- One-time BOOTSTRAP for the historical gap the narrow intake-salesforce crawl
-- does not yet reach. deal_source='manual_export'; a sf_crawl row with the same
-- dedup_key (normalized name | close_date | round(price/1000)) SUPERSEDES these.
-- IDEMPOTENT: re-running replaces the manual_export set only. Reversible:
--   DELETE FROM public.sjc_deal_ingest WHERE deal_source='manual_export';
-- NOTE: the export includes both-side / referral / outside-fee duplicate rows
-- (e.g. Leeds AL, Lawton OK, Paris/Washington PA appear twice) -> collapse on
-- dedup_key in the consuming view, NOT here.
-- ============================================================================

create table if not exists public.sjc_deal_ingest (
  id bigserial primary key,
  deal_source text not null default 'manual_export',
  sf_deal_id text,
  import_batch text,
  dedup_key text,
  deal_name text, sales_price numeric, cap_rate numeric, close_date date,
  lead_broker text, team text, deal_type text, referral text,
  city text, state text, tenant text, building_sf numeric, deal_commission numeric,
  property_subtype text, seller_company text, buyer_company text,
  list_date date, listing_price numeric, marketing_cap_rate numeric,
  lease_term_years numeric, time_on_market_days numeric,
  raw jsonb, linked_property_id bigint, matched_sale_id bigint,
  created_at timestamptz default now()
);
create index if not exists ix_sjc_deal_ingest_dedup  on public.sjc_deal_ingest(dedup_key);
create index if not exists ix_sjc_deal_ingest_source on public.sjc_deal_ingest(deal_source);
create index if not exists ix_sjc_deal_ingest_sfid   on public.sjc_deal_ingest(sf_deal_id);

delete from public.sjc_deal_ingest where deal_source='manual_export';

DEAL_PROPERTY_SUBTYPE is Dialysis
Page is Commercial Sales Detail
Business Unit is Commercial
DEAL_STAGENAME is Closed IS
FEE_DEAL_STAGE is Closed IS',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
